var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`뭐야? 조명이 고장났나?`,JPN:`なんだ？　ライトが壊れたのか？`,ENG:`Huh? Who turned off all the lights?`,TWN:`怎麼啦？燈壞掉嗎？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`젠장, 하필 이런 타이밍에 전기가 나가면 어떡해!`,JPN:`くそ、よりによってこのタイミングで照明が壊れるなんて！`,ENG:`Damn, how come the electricity goes out at a time like this!?`,TWN:`可惡！竟然在這個種關鍵時刻沒電！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`어? 저기 봐! 불빛이다!`,JPN:`あ？　あれ見ろ！　明かりだ！`,ENG:`Huh? Hey, look! There's a light shining over there!`,TWN:`喔？你們看！有火光！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`못된 악당들은 혼내 줘야 해.`,JPN:`悪い悪党は懲らしめないと。`,ENG:`I'm going to punish all those bad villains.`,TWN:`我要教訓那些壞人！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`악당들은 자기만 행복해지려고 착한 사람들을 괴롭히니까.`,JPN:`悪党は自分だけ幸せになるために、優しい人たちをいじめるから。`,ENG:`Villains hurt other people so they can be happy.`,TWN:`誰叫壞人欺負那些想要變幸福的好人！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`하지만 만약, 행복해지는 방법을 몰라서 그렇다면……`,JPN:`でももしかして、幸せになれる方法がわからなくてそうしてるのなら……`,ENG:`But, if they do that because they don't know how to be happy...`,TWN:`要是有人不知道變幸福的方法……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`내가 알려 줄게!`,JPN:`私が教えてあげる！`,ENG:`Then I'll have to teach them!`,TWN:`我會告訴你的！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`시그마 프로토콜! 최대 개방!`,JPN:`シグマ・プロトコル！　最大開放！`,ENG:`Sigma Protocol! Maximum output!`,TWN:`西格瑪協定！開放到最大！`},stage:{bg:`HAVEN_03`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`프로텍션 커넥트, 올 뉴 그린!!`,JPN:`プロテクション・コネクト、オールニューグリーン！！`,ENG:`Protection Connect, all systems green!!`,TWN:`防護連接，綠光閃閃！！`},stage:{bg:`HAVEN_03`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`놀이터를 주름 잡는 최종 보스! 시그마 등장이오!!`,JPN:`遊び場を牛耳る最終ボス！　シグマ参上！！`,ENG:`Final boss of the playground! Here comes Sigma!`,TWN:`控制遊樂園的最終BOSS！西格瑪登場！！`},stage:{bg:`HAVEN_01`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`PUPPET_NPC_SUPPLEMENT_NULL`,text:{KOREA:`으윽……!`,JPN:`ううっ……！`,ENG:`Ngh...!`,TWN:`呃……！`},stage:{bg:`COLOSSEUM`,slots:{L:null,C:{char_id:`PUPPET_NPC_SUPPLEMENT_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`SWORD_OZ_NULL_NULL`,text:{KOREA:`수, 수아야! 정신이 들어?!`,JPN:`こ、コトリちゃん！　気がついた！？`,ENG:`S-Skia! Are you all right?!`,TWN:`蘇…蘇亞！你恢復意識了嗎？！`},stage:{bg:`COLOSSEUM`,slots:{L:{char_id:`PUPPET_NPC_SUPPLEMENT_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SWORD_OZ_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L21_1`,type:`dialog`,speaker:`PUPPET_NPC_SUPPLEMENT_NULL`,text:{KOREA:`리온……? 무슨 일이 벌어진 거야?`,JPN:`リオン……？　いったい何が起こったの？`,ENG:`Liona...? What just happened?`,TWN:`萊恩……？發生什麼事？`},stage:{bg:`COLOSSEUM`,slots:{L:{char_id:`PUPPET_NPC_SUPPLEMENT_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SWORD_OZ_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L23_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`뭐야? 독사과가 오류를 일으켰다고?`,JPN:`どういうこと？　毒リンゴにエラーが？`,ENG:`Huh? Poison Apple got an error?`,TWN:`搞什麼？毒蘋果發生錯誤嗎？`},stage:{bg:`COLOSSEUM`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`설마 저 계집애 짓인가……!`,JPN:`まさかこれもあの小娘の仕業かしら……！`,ENG:`Is it because of that brat...?!`,TWN:`難道是那丫頭搞的……！`},stage:{bg:`COLOSSEUM`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`나랑 술래잡기 할 사람! 여기 여기 붙어라!`,JPN:`私と追いかけっこする人！　みんな集まれ！`,ENG:`Who wants to play tag with me?!`,TWN:`誰要和我玩鬼抓人！來來來！`},stage:{bg:`COLOSSEUM`,slots:{L:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`SIGMA_RAS_NEXT_NULL`,face:`UNIT_LAUGH`}}}}];export{e as default};